(function() {
    "use strict";
    var DivaemojiData = {
        //baseURL: "https://github.githubassets.com/images/icons/emoji/",
        baseURL: "",
        data: {
            ac_t: "data:image/png;base64,",
            ac_s: "data:image/png;base64,",
            ac_x: "data:image/png;base64,",
            ac_o: "data:image/png;base64,",
            ac_l: "data:image/png;base64,",
            ac_r: "data:image/png;base64,",
            cs_u: "data:image/png;base64,",
            cs_l: "data:image/png;base64,",
            cs_d: "data:image/png;base64,",
            cs_r: "data:image/png;base64,",
            cs_s: "data:image/png;base64,",
            cs_sw: "data:image/png;base64,"
        }
    };

    function replaceEmojiShorthand(match, code, useNativeEmoji) {
        if (useNativeEmoji) {
            return match;
        }
        if (Object.prototype.hasOwnProperty.call(DivaemojiData.data, code)) {

            return `<img src="${DivaemojiData.baseURL}${DivaemojiData.data[code]}" alt="${code}" class="emoji" loading="lazy">`;
        }
        return match;
    }

    function emojifyHtml(html, useNativeEmoji) {
        if (html == null || html === '') {
            return html;
        }
        var text = String(html);
        return text
            .replace(
                /<(code|pre|script|template)[^>]*?>[\s\S]+?<\/(code|pre|script|template)>/gi,
                function(m) {
                    return m.replace(/:/g, '__colon__');
                }
            )
            .replace(/<!--[\s\S]+?-->/g, function(m) {
                return m.replace(/:/g, '__colon__');
            })
            .replace(/([a-z]{2,}:)?\/\/[^\s'">)]+/gi, function(m) {
                return m.replace(/:/g, '__colon__');
            })
            .replace(/:([a-z0-9_\-+]+?):/g, function(m, code) {
                return replaceEmojiShorthand(m, code, useNativeEmoji);
            })
            .replace(/__colon__/g, ':');
    }


    function installDivaEmoji(hook, vm) {
        hook.afterEach(function(html, next) {
            next(emojifyHtml(html));
        });
    }

    window.$docsify = window.$docsify || {};
    window.$docsify.plugins = [installDivaEmoji].concat(window.$docsify.plugins || []);

})();
